create table public.exercises (id uuid primary key default gen_random_uuid(),user_id uuid references auth.users(id) on delete cascade,name text not null check(char_length(btrim(name))>0),description text,category text not null check(category in('strength','cardio','mobility','recovery','rehab','plyometric','conditioning','custom')),movement_pattern text,primary_muscle_group text,secondary_muscle_groups text[],equipment text,default_tracking_type text not null default 'weight_reps' check(default_tracking_type in('weight_reps','bodyweight_reps','duration','distance_duration','calories_duration','repetitions','completion','custom')),is_archived boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.workout_templates(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,name text not null check(char_length(btrim(name))>0),description text,category text,estimated_duration_minutes integer check(estimated_duration_minutes is null or estimated_duration_minutes>0),notes text,is_archived boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(id,user_id));
create table public.workout_template_groups(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,workout_template_id uuid not null references public.workout_templates(id) on delete cascade,group_order integer not null check(group_order>=0),group_label text not null,group_type text not null default 'single' check(group_type in('single','superset','triset','circuit')),rounds integer check(rounds is null or rounds>0),rest_between_exercises_seconds integer check(rest_between_exercises_seconds is null or rest_between_exercises_seconds>=0),rest_after_group_seconds integer check(rest_after_group_seconds is null or rest_after_group_seconds>=0),notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(id,user_id));
create table public.workout_template_exercises(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,workout_template_id uuid not null references public.workout_templates(id) on delete cascade,workout_template_group_id uuid not null references public.workout_template_groups(id) on delete cascade,exercise_id uuid not null references public.exercises(id),exercise_order integer not null check(exercise_order>=0),display_label text not null,tracking_type text not null,target_sets integer check(target_sets is null or target_sets>0),target_reps_min integer,target_reps_max integer,target_weight numeric,target_duration_seconds integer,target_distance numeric,distance_unit text,tempo text,rest_after_exercise_seconds integer,notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(id,user_id));
create table public.workout_template_sets(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,workout_template_exercise_id uuid not null references public.workout_template_exercises(id) on delete cascade,set_number integer not null check(set_number>0),set_type text not null default 'working' check(set_type in('warmup','working','backoff','drop','failure','amrap','timed','distance','custom')),target_reps integer,target_reps_min integer,target_reps_max integer,target_weight numeric,target_duration_seconds integer,target_distance numeric,distance_unit text,is_optional boolean not null default false,notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(workout_template_exercise_id,set_number),unique(id,user_id));
create table public.planned_workouts(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,workout_template_id uuid references public.workout_templates(id) on delete set null,planned_activity_id uuid references public.planned_activities(id) on delete set null,planned_activity_occurrence_id uuid references public.planned_activity_occurrences(id) on delete set null,user_protocol_id uuid references public.user_protocols(id) on delete set null,name text not null,description text,scheduled_date date not null,scheduled_time time,estimated_duration_minutes integer,status text not null default 'planned' check(status in('draft','planned','in_progress','completed','skipped','cancelled')),notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(id,user_id));
create unique index planned_workouts_occurrence_unique on public.planned_workouts(planned_activity_occurrence_id) where planned_activity_occurrence_id is not null;
create table public.planned_workout_exercises(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,planned_workout_id uuid not null references public.planned_workouts(id) on delete cascade,source_template_exercise_id uuid references public.workout_template_exercises(id) on delete set null,exercise_id uuid references public.exercises(id) on delete set null,exercise_name text not null,group_order integer not null,group_label text not null,group_type text not null,exercise_order integer not null,display_label text not null,tracking_type text not null,tempo text,rest_after_exercise_seconds integer,notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(id,user_id));
comment on table public.planned_workout_exercises is 'Date-specific immutable snapshots of exercise names, grouping, and order.';
create table public.planned_workout_sets(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,planned_workout_id uuid not null references public.planned_workouts(id) on delete cascade,planned_workout_exercise_id uuid not null references public.planned_workout_exercises(id) on delete cascade,source_template_set_id uuid references public.workout_template_sets(id) on delete set null,set_number integer not null,set_type text not null default 'working',target_reps integer,target_reps_min integer,target_reps_max integer,target_weight numeric,target_duration_seconds integer,target_distance numeric,distance_unit text,is_optional boolean not null default false,notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(planned_workout_exercise_id,set_number));
create table public.workout_sessions(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,planned_workout_id uuid references public.planned_workouts(id) on delete set null,planned_activity_occurrence_id uuid references public.planned_activity_occurrences(id) on delete set null,name text not null,session_date date not null,status text not null default 'in_progress' check(status in('in_progress','completed','abandoned')),started_at timestamptz not null,ended_at timestamptz,duration_seconds integer check(duration_seconds is null or duration_seconds>=0),perceived_difficulty integer check(perceived_difficulty is null or perceived_difficulty between 1 and 10),energy_before integer check(energy_before is null or energy_before between 1 and 10),energy_after integer check(energy_after is null or energy_after between 1 and 10),notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),check(ended_at is null or ended_at>=started_at),unique(id,user_id));
create unique index workout_sessions_one_active on public.workout_sessions(planned_workout_id) where planned_workout_id is not null and status='in_progress';
create table public.workout_session_exercises(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,workout_session_id uuid not null references public.workout_sessions(id) on delete cascade,planned_workout_exercise_id uuid references public.planned_workout_exercises(id) on delete set null,exercise_id uuid references public.exercises(id) on delete set null,exercise_name text not null,group_order integer not null,group_label text not null,group_type text not null,exercise_order integer not null,display_label text not null,tracking_type text not null,notes text,is_completed boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(id,user_id));
create table public.workout_session_sets(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,workout_session_id uuid not null references public.workout_sessions(id) on delete cascade,workout_session_exercise_id uuid not null references public.workout_session_exercises(id) on delete cascade,planned_workout_set_id uuid references public.planned_workout_sets(id) on delete set null,set_number integer not null,set_type text not null default 'working',planned_reps integer,planned_reps_min integer,planned_reps_max integer,planned_weight numeric,planned_duration_seconds integer,planned_distance numeric,actual_reps integer,actual_weight numeric,actual_duration_seconds integer,actual_distance numeric,distance_unit text,status text not null default 'pending' check(status in('pending','completed','skipped')),completed_at timestamptz,notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(workout_session_exercise_id,set_number));
alter table public.protocol_template_activities add column workout_template_id uuid references public.workout_templates(id) on delete set null;
create index workout_templates_user_idx on public.workout_templates(user_id,is_archived);create index workout_groups_template_idx on public.workout_template_groups(workout_template_id,group_order);create index workout_exercises_template_idx on public.workout_template_exercises(workout_template_id,workout_template_group_id,exercise_order);create index planned_workouts_user_date_idx on public.planned_workouts(user_id,scheduled_date);create index planned_workouts_user_status_idx on public.planned_workouts(user_id,status);create index workout_sessions_user_date_idx on public.workout_sessions(user_id,session_date);create index workout_sessions_user_status_idx on public.workout_sessions(user_id,status);create index workout_session_sets_session_idx on public.workout_session_sets(workout_session_id,status);
do $$ declare t text; begin foreach t in array array['exercises','workout_templates','workout_template_groups','workout_template_exercises','workout_template_sets','planned_workouts','planned_workout_exercises','planned_workout_sets','workout_sessions','workout_session_exercises','workout_session_sets'] loop execute format('alter table public.%I enable row level security',t);execute format('create policy %I on public.%I for select to authenticated using (user_id=(select auth.uid())%s)',t||'_select',t,case when t='exercises' then ' or user_id is null' else '' end);execute format('create policy %I on public.%I for insert to authenticated with check (user_id=(select auth.uid()))',t||'_insert',t);execute format('create policy %I on public.%I for update to authenticated using (user_id=(select auth.uid())) with check (user_id=(select auth.uid()))',t||'_update',t);execute format('create policy %I on public.%I for delete to authenticated using (user_id=(select auth.uid()))',t||'_delete',t);end loop;end $$;
do $$ declare t text; begin foreach t in array array['exercises','workout_templates','workout_template_groups','workout_template_exercises','workout_template_sets','planned_workouts','planned_workout_exercises','planned_workout_sets','workout_sessions','workout_session_exercises','workout_session_sets'] loop execute format('create trigger %I before update on public.%I for each row execute function public.axvital_planning_set_updated_at()',t||'_set_updated_at',t);end loop;end $$;
